"""
Patch installer -- full campaign pipeline.
Run from ~/workspace:  python install_campaign_worker.py
"""
import base64, os

def write(path, b64):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else ".", exist_ok=True)
    open(path,"wb").write(base64.b64decode(b64))
    print("  wrote " + path)

FILES = {
    'workers/beezy_campaign.py': '',
    'pacing/orchestrator.py': '',
}
for path, b64 in FILES.items():
    write(path, b64)
print("""
Done.

Pipeline for approved klaviyo_campaign / sniper_followup slots:
  1. Anthropic API  -> subject, preview, body, image_prompt
  2. Higgsfield REST -> hero image (image_gen.py)
  3. Shopify Files  -> CDN URL for image
  4. Build branded HTML email
  5. Klaviyo template (REST)
  6. Klaviyo DRAFT campaign (Smart Sending OFF, 7 UTMs, locked config)
  7. Assign template to message
  8. Slack Block Kit notify with Open in Klaviyo button

Boris reviews in Klaviyo -> schedules -> done.
""")
